sql:
SELECT AVG(weight_kg) AS average_weight_kg
FROM growth_standards
WHERE growth_parameter = 'weight';

SELECT unit_system, COUNT(standard_id) AS standard_count
FROM growth_standards
GROUP BY unit_system;

SELECT COUNT(birth_weight) AS total_infants_with_birth_weight
FROM infants
WHERE birth_weight IS NOT NULL;

SELECT age_group
FROM growth_standards
WHERE standard_id = 1;

SELECT record_date, height_cm, weight_kg, notes 
FROM growth_records 
WHERE infant_id = 0 AND record_date > '2023-01-01';

SELECT first_name, last_name
FROM infants
ORDER BY date_of_birth DESC;

SELECT MAX(weight_kg) AS highest_average_weight_kg
FROM growth_standards
WHERE growth_parameter = 'weight';
